    use super::*;

    #[test]
    fn message_types() {
        let text = Message::text("hello");
        assert!(text.is_text());
        assert_eq!(text.into_text(), Some("hello".into()));

        let binary = Message::binary(vec![1, 2, 3]);
        assert!(binary.is_binary());

