        assert!(close.is_close());
    }

    #[test]
    fn sse_event_format() {
        let event = Event::new("hello world");
        assert_eq!(event.to_string(), "data: hello world\n\n");

        let typed = Event::new("data").event("message").id("1");
        assert!(typed.to_string().contains("event: message"));
        assert!(typed.to_string().contains("id: 1"));

        let multiline = Event::new("line1\nline2");
        assert!(multiline.to_string().contains("data: line1\n"));
        assert!(multiline.to_string().contains("data: line2\n"));
    }

    #[test]
    fn ws_accept_key() {
        // Known test vector from RFC 6455
        let key = "dGhlIHNhbXBsZSBub25jZQ==";
        let accept = compute_accept_key(key);
        assert_eq!(accept, "s3pPLMBiTxaQ9kYGzzhZRbK+xOo=");
    }

    #[tokio::test]
    async fn websocket_send_recv() {
        let (tx1, rx1) = mpsc::channel(16);
        let (tx2, rx2) = mpsc::channel(16);

        let mut ws = WebSocket {
            rx: rx1,
            tx: tx2,
            closed: false,
        };

        // Simulate receiving a message
        tx1.send(Ok(Message::text("hello"))).await.unwrap();

        let msg = ws.recv().await.unwrap().unwrap();
        assert_eq!(msg.into_text(), Some("hello".into()));

        // Send a message
        ws.send_text("world").await.unwrap();
        let sent = rx2.recv().await.unwrap();
        assert_eq!(sent.into_text(), Some("world".into()));
    }
}
