mod e2e_tests {
    use super::*;
    use crate::lab::LabRuntime;
    use tracing::info;

    #[test]
    fn e2e_websocket_echo() {
        let lab = LabRuntime::builder()
            .with_tracing("web_ws=debug")
            .build();

        lab.run(async {
            info!("Testing WebSocket echo server");

            let router = Router::new()
                .get("/ws", |ws: WebSocketUpgrade| async move {
                    ws.on_upgrade(|mut socket| async move {
                        info!("WebSocket connection established");
                        while let Some(msg) = socket.recv().await {
                            match msg {
                                Ok(Message::Text(text)) => {
                                    info!(text = %text, "Received text, echoing");
                                    socket.send_text(format!("Echo: {}", text)).await.ok();
                                }
                                Ok(Message::Close(_)) => {
                                    info!("Client closed connection");
                                    break;
                                }
                                Err(e) => {
                                    info!(error = %e, "WebSocket error");
                                    break;
                                }
                                _ => {}
                            }
                        }
                    })
                });

            // Verify upgrade response
            let req = Request::get("/ws")
                .header("connection", "Upgrade")
                .header("upgrade", "websocket")
                .header("sec-websocket-key", "dGVzdGtleQ==")
                .header("sec-websocket-version", "13")
                .unwrap();

            let resp = router.call(req).await.unwrap();
            assert_eq!(resp.status(), StatusCode::SWITCHING_PROTOCOLS);
            assert!(resp.headers().get("sec-websocket-accept").is_some());

            info!("E2E WebSocket test passed");
        });
    }

    #[test]
    fn e2e_sse_stream() {
        let lab = LabRuntime::builder()
            .with_tracing("web_sse=debug")
            .build();

        lab.run(async {
            info!("Testing SSE streaming");

            let router = Router::new()
                .get("/events", || async {
                    let events = stream::iter(vec![
                        Event::new("event 1").id("1"),
                        Event::new("event 2").id("2").event("update"),
                        Event::new("event 3").id("3"),
                    ]);
                    Sse::new(events)
                });

            let req = Request::get("/events").unwrap();
            let resp = router.call(req).await.unwrap();

            assert_eq!(resp.status(), 200);
            assert_eq!(
                resp.headers().get("content-type").unwrap(),
                "text/event-stream"
            );

            info!("E2E SSE test passed");
        });
    }
}
